noncompliant:
// Noncompliant: Simple switch with only 2 cases
int processGrade(char grade) {
    switch (grade) {
        case 'A': return 90;
        case 'B': return 80;
        default: return 0;
    }
}

compliant:
// Compliant: Simple if statement is clearer
int processGrade(char grade) {
    if (grade == 'A') {
        return 90;
    } else if (grade == 'B') {
        return 80;
    } else {
        return 0;
    }
}
